#include <stdio.h>
#include <stdlib.h>

int gcd_int(int a, int b) {
    while (b) {
        int t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        while (Q--) {
            int L, R; scanf("%d %d", &L, &R);
            int ans = 1; // minimum possible GCD
            for (int i = L-1; i < R-1; ++i) {
                for (int j = i+1; j < R; ++j) {
                    int g = gcd_int(A[i], A[j]);
                    if (g > ans) ans = g;
                }
            }
            printf("%d\n", ans);
        }
        free(A);
    }
    return 0;
}

